/**
 * Constrain a numeric value to the inclusive range [min, max].
 *
 * Throws:
 *  - TypeError if any argument is not a finite number (NaN or ±Infinity or non-number).
 *  - RangeError if min > max.
 */
export function clamp(value: number, min: number, max: number): number {
  // Defensive check: ensure exactly three args were provided to avoid surprising behavior
  if (arguments.length < 3) {
    throw new TypeError('clamp: requires value, min, and max arguments');
  }

  // Validate types and finiteness at runtime to provide clear errors.
  const isFiniteNumber = (x: unknown): x is number => typeof x === 'number' && Number.isFinite(x);

  if (!isFiniteNumber(value)) {
    throw new TypeError('clamp: value must be a finite number');
  }
  if (!isFiniteNumber(min)) {
    throw new TypeError('clamp: min must be a finite number');
  }
  if (!isFiniteNumber(max)) {
    throw new TypeError('clamp: max must be a finite number');
  }

  if (min > max) {
    throw new RangeError('clamp: min must be <= max');
  }

  if (value < min) return min;
  if (value > max) return max;
  return value;
}


--- tests/clamp.test.ts ---
import { clamp } from '../src/index';

describe('clamp', () => {
  test('returns the value when within bounds', () => {
    expect(clamp(5, 1, 10)).toBe(5);
    expect(clamp(1.5, 1, 2)).toBe(1.5);
  });

  test('returns min when value is below min', () => {
    expect(clamp(-3, 0, 100)).toBe(0);
  });

  test('returns max when value is above max', () => {
    expect(clamp(300, 0, 200)).toBe(200);
  });

  test('inclusive bounds: equals min or max returns value', () => {
    expect(clamp(2, 2, 5)).toBe(2);
    expect(clamp(5, 1, 5)).toBe(5);
  });

  test('throws RangeError when min > max', () => {
    expect(() => clamp(1, 10, 5)).toThrow(RangeError);
  });

  test('throws TypeError for NaN or Infinity inputs', () => {
    expect(() => clamp(NaN, 0, 1)).toThrow(TypeError);
    expect(() => clamp(0, NaN as any, 1)).toThrow(TypeError);
    expect(() => clamp(0, 0, Infinity as any)).toThrow(TypeError);
    expect(() => clamp(Infinity as any, 0, 1)).toThrow(TypeError);
  });

  test('works with negative ranges', () => {
    expect(clamp(-10, -20, -5)).toBe(-10);
    expect(clamp(-30, -20, -5)).toBe(-20);
    expect(clamp(0, -5, 5)).toBe(0);
  });

  test('non-number inputs throw TypeError at runtime', () => {
    // @ts-ignore - intentional runtime misuse tests
    expect(() => clamp('1', 0, 2)).toThrow(TypeError);
    // @ts-ignore
    expect(() => clamp(1, null, 2)).toThrow(TypeError);
  });
});


